#include <stdio.h>
#include <math.h>

long long maxLayers(long long N) {
    long long k = (long long)((sqrt(8.0 * N + 1) - 1) / 2);
    while ((k + 1) * (k + 2) / 2 <= N) ++k;
    while (k * (k + 1) / 2 > N) --k;
    return k;
}

int main(void) {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        printf("%lld\n", maxLayers(N));
    }
    return 0;
}

