import sys, math

def max_layers(N: int) -> int:
    # Use integer sqrt to avoid floating point errors
    k = (math.isqrt(8 * N + 1) - 1) // 2
    while (k + 1) * (k + 2) // 2 <= N:
        k += 1
    while k * (k + 1) // 2 > N:
        k -= 1
    return k

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        N = int(data[idx]); idx += 1
        out.append(str(max_layers(N)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

